import Sidebar from "../components/Sidebar";

export default function TeamLeadDashboard() {
  return (
    <div className="min-h-screen bg-[#eef4fb] flex">
      <Sidebar />

      {/* Main Content Area - pushed right by 268px to clear the sidebar */}
      <div className="flex-1 ml-[268px] p-8">
        <div className="max-w-5xl mx-auto">
          <header className="mb-8">
            <h1 className="text-3xl font-extrabold text-[#122033] tracking-tight">Knowledge Base Management</h1>
            <p className="text-[#64748b] mt-2">Add, edit, or remove policies from the live database.</p>
          </header>

          <div className="bg-white p-8 rounded-[20px] shadow-sm border border-[#dbe7f3]">
            <h2 className="text-xl font-bold text-[#122033] mb-4">Add New Policy</h2>
            <p className="text-[#64748b]">Form temporarily hidden while updating layout.</p>
          </div>
        </div>
      </div>
    </div>
  );
}
